#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define int long long
using namespace std;
const int N=1e7+10,Mod=20101009,M4=15075757,M2=10050505;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
bool vs[N];int mu[N],pm[N>>2],s[N],cnt;
inline void Init(int mx)
{
	vs[1]=mu[1]=1;rep(2,mx,i)
	{
		if(!vs[i])mu[pm[++cnt]=i]=-1; rep(1,cnt,j)
		{
			if(i*pm[j]>mx)break;
			mu[pm[j]*i]=(i%pm[j]==0?0:-mu[i]);
			vs[pm[j]*i]=1;if(i%pm[j]==0)break;
		}
	}
	rep(1,mx,i)(s[i]=mu[i]*i%Mod*i%Mod+Mod)%Mod;
	rep(2,mx,i)s[i]=(s[i]+s[i-1])%Mod;
}
inline int S_m(int n,int m){return 1ll*n*(n+1)%Mod*m%Mod*(m+1)%Mod*M4%Mod;}
inline int Sum(int n,int m)
{
	int ans=0;for(int l=1,r=0;l<=n;l=r+1)
	{
		r=min(n/(n/l),m/(m/l));
		ans=(ans+1ll*(s[r]-s[l-1]+Mod)%Mod*S_m(n/l,m/l)%Mod)%Mod;
	}return ans;
}
signed main()
{
	Init(N-10);int n=read(),m=read();if(n>m)swap(n,m);
	int ans=0;for(int l=1,r=0;l<=n;l=r+1)
	{
		r=min(n/(n/l),m/(m/l));
		ans=(ans+1ll*(r-l+1)*(l+r)%Mod*M2%Mod*Sum(n/l,m/l)%Mod)%Mod;
	}
	printf("%lld\n",ans);return 0;
}
